def canFinish(numCourses, prerequisites):
    graph = defaultdict(list)
    for a, b in prerequisites:
        graph[a].append(b)
    visiting = set()
    def dfs(node):
        if node in visiting:
            return False
        visiting.add(node)
        for nei in graph[node]:
            if not dfs(nei):
                return False
        visiting.remove(node)
        graph[node] = []
        return True
    return all(dfs(i) for i in range(numCourses))

