            if c not in node.children:
                node.children[c] = WordDictionary()
            node = node.children[c]
        node.is_end = True
    def search(self, word):
        def dfs(j, node):
            for i in range(j, len(word)):
                c = word[i]
                if c == '.':
                    return any(dfs(i+1, child) for child in node.children.values())
                if c not in node.children:
                    return False
                node = node.children[c]
            return node.is_end
        return dfs(0, self)

