        if i == len(word):
            return True
        if r<0 or c<0 or r>=rows or c>=cols or (r,c) in path or board[r][c]!=word[i]:
            return False
        path.add((r,c))
        res = dfs(r+1,c,i+1) or dfs(r-1,c,i+1) or dfs(r,c+1,i+1) or dfs(r,c-1,i+1)
        path.remove((r,c))
