def maxProfit(prices):
    dp = {}
    def dfs(i, buying):
        if i >= len(prices):
            return 0
        if (i, buying) in dp:
            return dp[(i, buying)]
        if buying:
            buy = dfs(i+1, not buying) - prices[i]
            skip = dfs(i+1, buying)
            dp[(i, buying)] = max(buy, skip)
        else:
            sell = dfs(i+2, not buying) + prices[i]
            skip = dfs(i+1, buying)
            dp[(i, buying)] = max(sell, skip)
        return dp[(i, buying)]
    return dfs(0, True)

